let authToken = localStorage.getItem('authToken') || null;
   
const API_BASE_URL = window.location.origin;

// ============================================
// APP FILTERING SYSTEM - USING LESSON_ID
// ============================================

const APP_LESSON_MAP = {
    'mathease': {
        lessonId: 1,
        name: 'MathEase'  // MathEase uses lesson_id = 1
    },
    'factorial': {
        lessonId: 3,
        name: 'FactoLearn'
    },
    'polylearn': {
        lessonId: 2,
        name: 'PolyLearn'
    }
};

// ============================================
// MATHEASE CONSTANTS - FORCE LESSON_ID = 1
// ============================================
const MATHEASE_LESSON_ID = 1; // Fixed for MathEase app

// Para madaling gamitin
const CURRENT_LESSON_ID = 1; // MathEase only
const CURRENT_APP_NAME = 'MathEase';

function getCurrentApp() {
    return localStorage.getItem('selectedApp') || 'mathease'; // MathEase ang default
}

function getCurrentAppLessonId() {
    // Kunin ang app selection ng user
    const selectedApp = localStorage.getItem('selectedApp') || 'mathease';
    
    // Return appropriate lesson_id based on selected app
    const appMap = {
        'mathease': 1,      // MathEase = 1
        'polylearn': 2,      // PolyLearn = 2
        'factorial': 3       // FactoLearn = 3
    };
    
    return appMap[selectedApp] || 1; // Default to 1 for MathEase
}

// Example API call - lahat ng user ay makakakita ng MathEase data
// kung naka-select sila ng MathEase
fetch(`/api/topics/progress?lesson_id=${getCurrentAppLessonId()}`, {
    headers: { 'Authorization': `Bearer ${authToken}` }
});

// Get the filter parameter for API calls
function getAppFilterParam() {
    const app = getCurrentApp();
    return APP_LESSON_MAP[app]?.name.toLowerCase() || 'mathease';
}

function addAppFilterToUrl(url) {
    const separator = url.includes('?') ? '&' : '?';
    // FORCE MathEase: Laging lesson_id=1
    return `${url}${separator}lesson_id=${MATHEASE_LESSON_ID}`;
}

// ============================================
// ✅ Fetch practice exercises by lesson ID
// ============================================
async function fetchPracticeByLesson(lessonId) {
    console.log(`📝 Fetching practice exercises for lesson ${lessonId}`);
    
    try {
        const token = localStorage.getItem('authToken') || authToken;
        if (!token) return [];
        
        const response = await fetch(`/api/practice/lesson/${lessonId}?lesson_id=1`, {
            headers: {
                'Authorization': `Bearer ${token}`,
                'Accept': 'application/json'
            }
        });
        
        if (response.ok) {
            const data = await response.json();
            console.log(`✅ Found practice for lesson ${lessonId}:`, data);
            
            if (data.success && data.exercises) {
                return data.exercises;
            }
        }
        
        // If endpoint doesn't exist, return mock exercises based on lesson
        return getMockPracticeByLesson(lessonId);
        
    } catch (error) {
        console.error('Error fetching practice by lesson:', error);
        return getMockPracticeByLesson(lessonId);
    }
}
// ============================================
// ✅ FIXED: Ensure Progress Summary Shows on Dashboard
// ============================================
function ensureProgressSummaryShows() {
    console.log('📊 Ensuring progress summary shows on dashboard...');
    
    const lessonsCount = document.getElementById('lessonsCount');
    const exercisesCount = document.getElementById('exercisesCount');
    const quizScore = document.getElementById('quizScore');
    const avgTime = document.getElementById('avgTime');
    
    if (!lessonsCount || !exercisesCount || !quizScore || !avgTime) {
        console.log('⚠️ Progress summary elements not found, will retry');
        setTimeout(ensureProgressSummaryShows, 500);
        return;
    }
    
    // Force update with data from PracticeState if available
    if (PracticeState.userPracticeProgress) {
        const stats = PracticeState.userPracticeProgress;
        lessonsCount.innerHTML = `${stats.lessons_completed || 0}<span class="item-unit">/${stats.total_lessons || 10}</span>`;
        exercisesCount.innerHTML = `${stats.exercises_completed || 0}<span class="item-unit">/20</span>`;
    }
    
    // Also try to fetch fresh data
    updateProgressSummaryCards();
    
    console.log('✅ Progress summary elements found and updated');
}
