// ============================================
// ✅ FIXED: Modified startQuizSystem to ensure timer runs
// ============================================
// Replace your existing startQuizSystem function with this one
async function startQuizSystem(quizId) {
    console.log("🎯 Starting QUIZ ID:", quizId);
    
    try {
        const token = localStorage.getItem('authToken') || authToken;
        const userJson = localStorage.getItem('mathhub_user');
        
        if (!token || !userJson) {
            showNotification('Please login first', 'error');
            return;
        }
        
        const user = JSON.parse(userJson);
        
        // Show loading
        showQuizModalLoading();
        
        // Try to start quiz attempt
        let attempt = null;
        let questions = [];
        
        // Method 1: Try to start quiz via API
        try {
            const attemptResponse = await fetch(`/api/quiz/${quizId}/start`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ user_id: user.id })
            });
            
            if (attemptResponse.ok) {
                const attemptData = await attemptResponse.json();
                if (attemptData.success && attemptData.attempt) {
                    attempt = attemptData.attempt;
                }
            }
        } catch (e) {
            console.log('⚠️ Could not start quiz via API:', e.message);
        }
        
        // If no attempt, create local attempt
        if (!attempt) {
            attempt = {
                attempt_id: Date.now(),
                quiz_id: quizId,
                user_id: user.id,
                start_time: new Date().toISOString()
            };
        }
        
        // Method 2: Try to fetch questions
        try {
            const questionsResponse = await fetch(`/api/quiz/${quizId}/questions?lesson_id=1`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            
            if (questionsResponse.ok) {
                const questionsData = await questionsResponse.json();
                if (questionsData.success && questionsData.questions) {
                    questions = questionsData.questions;
                }
            }
        } catch (e) {
            console.log('⚠️ Could not fetch questions via API:', e.message);
        }
        
        // If no questions, create demo questions
        if (!questions || questions.length === 0) {
            console.log('📝 Using demo questions');
            questions = getDemoQuestions(quizId);
        }
        
        // Calculate total time (60 seconds per question)
        const totalTime = questions.length * 60;
        
        // Initialize quiz state
        QuizSystem.currentQuiz = quizId;
        QuizSystem.currentAttemptId = attempt.attempt_id;
        QuizSystem.questions = questions;
        QuizSystem.currentIndex = 0;
        QuizSystem.userAnswers = {};
        QuizSystem.submittedAnswers = {};
        QuizSystem.startTime = Date.now();
        QuizSystem.totalTime = totalTime;
        QuizSystem.timeLeft = totalTime;
        QuizSystem.stats = { correct: 0, wrong: 0, score: 0 };
        QuizSystem.answerResults = {};
        
        console.log(`✅ Quiz initialized with ${questions.length} questions, ${totalTime} seconds`);
        
        // Show quiz modal
        showQuizSystemModal();
        
        // Load first question
        loadQuizSystemQuestion(0);
        
        // ⚠️ REMOVE OR COMMENT OUT THESE LINES:
        // ensureTimerDisplay();        ← DELETE THIS LINE
        // console.log('⏱️ Starting quiz timer now...'); ← DELETE THIS LINE
        // startQuizSystemTimer();      ← DELETE THIS LINE
        
        // ✅ The universal timer will start automatically via showQuizSystemModal override
        
    } catch (error) {
        console.error('❌ Error starting quiz:', error);
        showNotification('Failed to start quiz: ' + error.message, 'error');
        closeQuizModal();
    }
}
// ============================================
// 🚨 SIMPLE TIMER FIX - Updates the existing timer
// ============================================
(function ensureTimerRuns() {
    console.log('⏱️ Applying timer safety check');
    
    // Check every second if quiz is active but timer not running
    setInterval(() => {
        const quizModal = document.getElementById('quizModal');
        if (quizModal && quizModal.style.display === 'flex' && QuizSystem.timeLeft !== undefined) {
            
            // Check if timer is not running but should be
            const timeLeft = QuizSystem.timeLeft;
            const timerRunning = QuizSystem.timerInterval !== null;
            
            if (timeLeft > 0 && !timerRunning) {
                console.log('⏱️ Timer should be running but is not - restarting');
                startQuizSystemTimer();
            }
            
            // Always update display to ensure it's correct
            const timerDisplay = document.getElementById('quizTimerDisplay');
            if (timerDisplay) {
                const minutes = Math.floor(QuizSystem.timeLeft / 60);
                const seconds = QuizSystem.timeLeft % 60;
                timerDisplay.textContent = `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
            }
        }
    }, 1000);
})();
// ============================================
// ✅ Reset Timer Display - Sets the initial time
// ============================================
function resetTimerDisplay() {
    console.log('⏱️ Resetting timer display');
    
    // Find the timer display in the quiz container
    const timerDisplay = document.getElementById('quizTimerDisplay');
    
    if (timerDisplay && QuizSystem.timeLeft) {
        const minutes = Math.floor(QuizSystem.timeLeft / 60);
        const seconds = QuizSystem.timeLeft % 60;
        timerDisplay.textContent = `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
        console.log(`⏱️ Timer reset to: ${timerDisplay.textContent}`);
    }
}

