// ============================================
// ✅ Helper: Generate Demo Questions
// ============================================
function generateDemoQuestions(quiz) {
    const questionCount = 5;
    const questions = [];
    
    for (let i = 0; i < questionCount; i++) {
        questions.push({
            question_id: i + 1,
            question_text: `Question ${i + 1}: ${quiz.title || 'Sample Quiz'} - Select the correct answer.`,
            options: [
                { id: 1, text: 'Option A', is_correct: i === 0 },
                { id: 2, text: 'Option B', is_correct: i === 1 },
                { id: 3, text: 'Option C', is_correct: i === 2 },
                { id: 4, text: 'Option D', is_correct: i === 3 }
            ]
        });
    }
    
    return questions;
}
// ============================================
// Helper function to manually load PolyLearn quizzes (Category 2)
// ============================================
function loadmatheaseQuizzes() {
    console.log('📚 Loading MathEase quizzes (Category 1)...');
    
    // Find PolyLearn category (ID 3)
    const mathEaseCategory = QuizState.quizCategories.find(c => c.category_id == 1);
    
    if (mathEaseCategory) {
        loadQuizzesForCategory(1);
    } else {
        // If categories not loaded yet, load them first
        loadQuizCategories().then(() => {
            loadQuizzesForCategory(1);
        });
    }
}


