function showQuizSystemModal() {
    console.log('📱 Showing quiz modal');
    
    const modal = document.getElementById('quizModal');
    if (!modal) {
        console.error('❌ Quiz modal not found');
        return;
    }
    
    // Update title
    const titleSpan = document.getElementById('quizModalTitle');
    if (titleSpan) {
        titleSpan.textContent = 'Quiz';
    }
    
    // SHOW MODAL
    modal.style.display = 'flex';
    document.body.classList.add('modal-open');
    
    // Make sure quiz container is visible
    const quizContainer = document.getElementById('quizContainer');
    if (quizContainer) {
        quizContainer.style.display = 'block';
    }
    
    // Make sure results container is hidden
    const resultsContainer = document.getElementById('quizResultsContainer');
    if (resultsContainer) {
        resultsContainer.style.display = 'none';
    }
    
    // ADJUST OPTIONS GRID
    const optionsGrid = document.getElementById('quizOptionsGridModal');
    if (optionsGrid) {
        optionsGrid.style.overflowY = 'auto';
        optionsGrid.style.maxHeight = '450px';
        optionsGrid.style.padding = '10px';
    }
    
    // Hide submit button initially
    const submitBtn = document.getElementById('submitQuizBtn');
    if (submitBtn) {
        submitBtn.style.display = 'none';
    }
    
    // DO NOT add any timer creation code here!
    // The timer is already in your HTML
}

