                        <path d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="${iconColor}" stroke-width="3" stroke-dasharray="${score}, 100" stroke-linecap="round"></path>
